import{c as t,Q as e,j as r,m as n}from"./chunks/framework.DpF7k2f3.js";const _=JSON.parse('{"title":"第2章 なぜ「まず乗れ」が合理的な戦略か","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ja/part1-cognition/chapter2.md","filePath":"ja/part1-cognition/chapter2.md"}'),o={name:"ja/part1-cognition/chapter2.md"};function i(p,a,l,h,c,s){return e(),r("div",null,[...a[0]||(a[0]=[n('<h1 id="第2章-なぜ「まず乗れ」が合理的な戦略か" tabindex="-1">第2章 なぜ「まず乗れ」が合理的な戦略か <a class="header-anchor" href="#第2章-なぜ「まず乗れ」が合理的な戦略か" aria-label="Permalink to &quot;第2章 なぜ「まず乗れ」が合理的な戦略か&quot;">​</a></h1><h2 id="本章で学べること" tabindex="-1">本章で学べること <a class="header-anchor" href="#本章で学べること" aria-label="Permalink to &quot;本章で学べること&quot;">​</a></h2><p>前一章读完你已经知道、AIアプリ開発は想像那样するほど高点くない。但是我猜你现在还是有点犹豫——「 барьерは思いのほか低いが、それでも準備ができた的感觉がない」。</p><p>это很正常。我见过太多人在「準備」这件事上一拖就是半年一年，等他觉得准备好了，机会窗口早关了。</p><p>この章では明確に説明します：<strong>AIアプリ開発において、「まず乗れ」はギャンブルではなく、最も効率的な合理的戦略です。</strong></p><p>具体的には次ことを理解できます：</p><ul><li>AI技術のスキル半減期がいかに短いか、準備ができた頃には的黄花菜都已凉</li><li>企業が本当に欲しいのは「全部理解できる人」ではなく「能动く人」</li><li>边干边学の効率是闭门苦读的2-3倍</li><li>「私は不够格」という这种感觉是个幻觉，以及如何与之和平共处</li></ul><hr><h2 id="_2-1-aiアプリ開発のスキル半減期は驚くほど短い" tabindex="-1">2.1 AIアプリ開発のスキル半減期は驚くほど短い <a class="header-anchor" href="#_2-1-aiアプリ開発のスキル半減期は驚くほど短い" aria-label="Permalink to &quot;2.1 AIアプリ開発のスキル半減期は驚くほど短い&quot;">​</a></h2><p>まず私の亲眼见证した事实を言います。</p><p>2022年10月、LangChainが刚发布的时候、私の友人はまるまる3个月把这套框架学透做了十几个demo、履歴書には明確に「LangChainをマスター」と記載。2023年初彼はこれで跳槽に成功し、給与が40%上昇した。</p><p>その後呢？2024年、LangChainチームはLangGraphを発表 전혀다른アーキテクチャ。2025年10月、LangChainは直接1.0バージョンを发布 entireフレームワークをゼロから書き直し。さて、どうなるでしょうか？彼が3个月で学んだ内容のほとんどはそのまま無効になった。</p><p><strong>これがAIアプリ開発の残酷な現実：あなたが学んでいるものは、まだ学び终わる前に既に時代遅れになっている可能性がある。</strong></p><hr><blockquote><p><strong>全文の翻訳は後日公開予定、しばらくお待ちください。中文版は今すぐ読めます。</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part1-cognition/chapter2.html">中文版阅读</a></p></blockquote>',15)])])}const u=t(o,[["render",i]]);export{_ as __pageData,u as default};
